import { Button } from "reactstrap";

import React, { useState } from "react";
import { useHistory } from "react-router-dom";
// ** Store
import { useSelector } from "react-redux";
import TruckListTable from "../common/TruckListTable";

const QualityCheck = ({ isViewOnly, title, returnUrl, status }) => {
  const history = useHistory();
  const UserDetails = useSelector((state) => (state && state.auth ? state.auth.userData : {}));
  const [tableFilter] = useState({
    plantIds: UserDetails.plantids,
    formType: "F",
    startCount: 0,
    rake: "Yes",
    vehicleStatus: status || "2,3,4,5,6",
  });

  const actionsCol = (row) => {
    let status = row.VECHICAL_STATUS;
    switch (status) {
      case "2":
        return !isViewOnly ? (
          <Button.Ripple color="primary" onClick={(e) => onUpdateStatus(row.PI_REFID)}>
            {"Quality Check"}
          </Button.Ripple>
        ) : (
          ""
        );
      case "3":
      case "4":
      case "5":
      case "6":
      case "0":
      case "7":
        return (
          <Button.Ripple
            color="primary"
            onClick={(e) => {
              history.push(`/QAView:${row.PI_REFID}/${returnUrl || "QC"}`);
            }}
          >
            {"View QC"}
          </Button.Ripple>
        );
      default:
        return "";
    }
  };

  const onUpdateStatus = (id) => {
    history.push(`/QC:${id}`);
  };

  return (
    <div>
      <TruckListTable postData={tableFilter} actionCell={actionsCol} title={title || "Quality Check"} hideFilter={isViewOnly} />
    </div>
  );
};

export default QualityCheck;
